import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { ROUTES } from "../../constants";
import "./Header.css";

const Header = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentLanguage, setCurrentLanguage] = useState('vi'); // 'vi' for Vietnamese, 'en' for English

  // Language translations
  const translations = {
    vi: {
      home: "Trang chủ",
      about: "Giới thiệu", 
      contact: "Liên hệ",
      login: "Đăng nhập",
      register: "Đăng ký"
    },
    en: {
      home: "Home",
      about: "About",
      contact: "Contact", 
      login: "Login",
      register: "Register"
    }
  };

  const t = translations[currentLanguage];

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  const changeLanguage = (lang) => {
    setCurrentLanguage(lang);
    // Here you can add localStorage to persist language preference
    localStorage.setItem('language', lang);
  };

  // Load saved language on component mount
  useEffect(() => {
    const savedLanguage = localStorage.getItem('language');
    if (savedLanguage && (savedLanguage === 'vi' || savedLanguage === 'en')) {
      setCurrentLanguage(savedLanguage);
    }
  }, []);

  return (
    <header className={`modern-header ${isScrolled ? "scrolled" : ""}`}>
      <div className="header-background">
        <div className="header-shape"></div>
        <div className="header-glow"></div>
      </div>

      <div className="header-container">
        <div className="header-content">
          {/* Logo */}
          <div className="logo-section">
            <Link to={ROUTES.HOME} className="logo-link">
              <div className="logo-icon">
                <span className="logo-text">G</span>
              </div>
              <span className="brand-name">G-Bridge</span>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <nav className="desktop-nav">
            <div className="nav-links">
              <Link to={ROUTES.HOME} className="nav-item">
                <span>{t.home}</span>
              </Link>
              <Link to={ROUTES.ABOUT} className="nav-item">
                <span>{t.about}</span>
              </Link>
              <Link to={ROUTES.CONTACT} className="nav-item">
                <span>{t.contact}</span>
              </Link>
            </div>
            {/* Sửa  */}

            {/* Language Switcher */}
            <div className="language-switcher">
              <button
                className={`flag-btn ${currentLanguage === 'vi' ? 'active' : ''}`}
                onClick={() => changeLanguage('vi')}
                title="Tiếng Việt"
              >
                🇻🇳
              </button>
              <button
                className={`flag-btn ${currentLanguage === 'en' ? 'active' : ''}`}
                onClick={() => changeLanguage('en')}
                title="English"
              >
                🇺🇸
              </button>
            </div>

            <div className="auth-section">
              <Link to={ROUTES.LOGIN} className="login-btn">
                {t.login}
              </Link>
              <Link to={ROUTES.REGISTER} className="register-btn">
                <span>{t.register}</span>
                <div className="btn-glow"></div>
              </Link>
            </div>
          </nav>

          {/* Mobile Menu Button */}
          <button
            className={`mobile-menu-btn ${isMobileMenuOpen ? "active" : ""}`}
            onClick={toggleMobileMenu}
            aria-label="Toggle menu"
          >
            <span></span>
            <span></span>
            <span></span>
          </button>
        </div>

        {/* Mobile Navigation */}
        <div className={`mobile-nav ${isMobileMenuOpen ? "active" : ""}`}>
          <div className="mobile-nav-content">
            {/* Mobile Language Switcher */}
            <div className="mobile-language-switcher">
              <button
                className={`mobile-flag-btn ${currentLanguage === 'vi' ? 'active' : ''}`}
                onClick={() => changeLanguage('vi')}
                title="Tiếng Việt"
              >
                🇻🇳 Tiếng Việt
              </button>
              <button
                className={`mobile-flag-btn ${currentLanguage === 'en' ? 'active' : ''}`}
                onClick={() => changeLanguage('en')}
                title="English"
              >
                🇺🇸 English
              </button>
            </div>

            <div className="mobile-links">
              <Link
                to={ROUTES.HOME}
                className="mobile-nav-item"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {t.home}
              </Link>
              <Link
                to={ROUTES.ABOUT}
                className="mobile-nav-item"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {t.about}
              </Link>
              <Link
                to={ROUTES.CONTACT}
                className="mobile-nav-item"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {t.contact}
              </Link>
            </div>

            <div className="mobile-auth">
              <Link
                to={ROUTES.LOGIN}
                className="mobile-login-btn"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {t.login}
              </Link>
              <Link
                to={ROUTES.REGISTER}
                className="mobile-register-btn"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {t.register}
              </Link>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
